DEF=dict(datum_x=235,datum_y=615,datum_size=36,num_x=655,num_y=525,num_size=118,
         date_color="#111111",num_color="#00e5ff",date_kern=0,num_kern=0)

def get_font(size):
    for path in ["/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
                 "/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf"]:
        try: return ImageFont.truetype(path,int(size))
        except: pass
    return ImageFont.load_default()

def draw_with_kern(draw,xy,text,fill,font,kern=0):
    x,y=xy
    if kern==0:
        draw.text((x,y),text,fill=fill,font=font,anchor="mm"); return
    total_w=sum(font.getlength(c)+kern for c in text)-kern
    cx=x-total_w/2
    bbox=font.getbbox("A"); cy=y-(bbox[3]-bbox[1])/2
    for char in text:
        draw.text((cx,cy),char,fill=fill,font=font,anchor="lt")
        cx+=font.getlength(char)+kern

def make_poster(pct,ds,coords=None):
    c={**DEF,**(coords or {})}
    img=Image.open(io.BytesIO(TPL)).copy()
    d=ImageDraw.Draw(img)
    fd=get_font(c["datum_size"]); fp=get_font(c["num_size"])
    s="+" if pct>=0 else "-"
    dk=int(float(c.get("date_kern",0))); nk=int(float(c.get("num_kern",0)))
    if dk==0: d.text((int(c["datum_x"]),int(c["datum_y"])),ds,fill=c["date_color"],font=fd,anchor="mm")
    else: draw_with_kern(d,(int(c["datum_x"]),int(c["datum_y"])),ds,c["date_color"],fd,dk)
    if nk==0: d.text((int(c["num_x"]),int(c["num_y"])),f"{s}{abs(pct):.2f}",fill=c["num_color"],font=fp,anchor="mm")
    else: draw_with_kern(d,(int(c["num_x"]),int(c["num_y"])),f"{s}{abs(pct):.2f}",c["num_color"],fp,nk)
    buf=io.BytesIO(); img.save(buf,format="PNG"); return buf.getvalue()

def extract_coords(data):
    keys=["datum_x","datum_y","datum_size","num_x","num_y","num_size","date_color","num_color","date_kern","num_kern"]
    return {k:data[k] for k in keys if k in data}

